// Calculate next retry with exponential backoff
const item = $input.first().json;
const retryCount = item.retry_count;
const category = item.error_category || 'UNKNOWN';

// Category-specific base delays (minutes)
const baseDelays = {
  'TRANSIENT': 5,
  'NETWORK': 5,
  'RATE_LIMIT': 10,
  'DEPENDENCY': 7.5,
  'AUTHENTICATION': 2.5,
  'UNKNOWN': 5
};

const baseDelay = baseDelays[category] || 5;
const maxDelay = 120; // 2 hours cap

// Exponential backoff: base * 2^retry_count
const exponentialDelay = baseDelay * Math.pow(2, retryCount);
const cappedDelay = Math.min(exponentialDelay, maxDelay);

// Add jitter (±10%)
const jitter = cappedDelay * 0.1 * (Math.random() * 2 - 1);
const finalDelay = cappedDelay + jitter;

const nextRetryAt = new Date(Date.now() + finalDelay * 60000);

return [{
  json: {
    ...item,
    calculated_delay_minutes: Math.round(finalDelay),
    next_retry_calculated: nextRetryAt.toISOString()
  }
}];

