// Determine next action for failed retry
const item = $input.first().json;
const newRetryCount = item.retry_count + 1;
const maxRetries = item.max_retries;

if (newRetryCount >= maxRetries) {
  return [{
    json: {
      ...item,
      new_status: 'PERMANENT_FAILURE',
      new_retry_count: newRetryCount,
      next_retry_at: null,
      is_permanent: true
    }
  }];
}

// Schedule next retry
const category = item.error_category || 'UNKNOWN';
const baseDelays = {
  'TRANSIENT': 5,
  'NETWORK': 5,
  'RATE_LIMIT': 10,
  'DEPENDENCY': 7.5,
  'AUTHENTICATION': 2.5,
  'UNKNOWN': 5
};
const baseDelay = baseDelays[category] || 5;
const maxDelay = 120;
const exponentialDelay = baseDelay * Math.pow(2, newRetryCount);
const cappedDelay = Math.min(exponentialDelay, maxDelay);
const jitter = cappedDelay * 0.1 * (Math.random() * 2 - 1);
const finalDelay = cappedDelay + jitter;
const nextRetryAt = new Date(Date.now() + finalDelay * 60000);

return [{
  json: {
    ...item,
    new_status: 'PENDING_RETRY',
    new_retry_count: newRetryCount,
    next_retry_at: nextRetryAt.toISOString(),
    is_permanent: false,
    retry_error: item.error?.message || 'Retry failed'
  }
}];

