// Aggregate processing results
const items = $input.all();

const resolved = items.filter(i => i.json.status === 'RESOLVED' || i.json.new_status === 'RESOLVED').length;
const permanent = items.filter(i => i.json.new_status === 'PERMANENT_FAILURE').length;
const pending = items.filter(i => i.json.new_status === 'PENDING_RETRY').length;

return [{
  json: {
    processed_at: new Date().toISOString(),
    total_processed: items.length,
    resolved: resolved,
    permanent_failures: permanent,
    rescheduled: pending,
    summary: `Processed ${items.length}: ${resolved} resolved, ${permanent} permanent, ${pending} rescheduled`
  }
}];

// No items to process
return [{
  json: {
    processed_at: new Date().toISOString(),
    total_processed: 0,
    resolved: 0,
    permanent_failures: 0,
    rescheduled: 0,
    summary: 'No items ready for retry'
  }
}];
